-- Chien -> humain, Anniversaire, Volume 7

insert into public.message_templates (user_id,title,content,tone,is_system,is_manual_only,occasion,animal_type,animal_direction) values

(null,'Pour ton anniversaire j''ai dormi sous la table pendant tout le repas.',$$Pour ton anniversaire j''ai dormi sous la table pendant tout le repas.
Pas couché. Assis. Droit. Avec dignité. Dans l''espoir raisonnable qu''une chose tomberait. Ou qu''une main compatissante descendrait. J''ai attendu une heure et demie. Rien. J''ai quand même pas bougé parce que l''espoir c''est un principe. Joyeux anniversaire, mon humain préféré.
Avec patience stratégique d''une heure trente et espoir intact malgré le bilan, — {prenom}, ton animal optimiste professionnel sous toutes les tables 🫥$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends pas pourquoi les gens font la vaisselle le soir même.',$$Joyeux anniversaire. Je comprends pas pourquoi les gens font la vaisselle le soir même.
La fête vient de finir. Tu es fatigué. Et tu attaques la vaisselle. Maintenant. Comme si les assiettes ne pouvaient pas attendre au matin. En fait je comprends ce principe. On a nos standards. Les tiens incluent la vaisselle le soir. Joyeux anniversaire, mon humain préféré.
Avec compréhension tardive de la vaisselle immédiate et respect total pour tes standards, — {prenom}, ton animal aux exigences comparables dans d''autres domaines 🍽️$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé comment tes mains racontent quand tu parles.',$$Pour ton anniversaire j''ai observé comment tes mains racontent quand tu parles.
Elles dessinent dans l''air. Elles indiquent des tailles. Elles ponctuent les moments importants. Tes mains racontent en même temps que ta voix. Deux narrations simultanées. Je regarde toujours tes mains quand tu parles. Elles en disent souvent plus que les mots. Joyeux anniversaire, mon humain préféré.
Avec lecture parallèle de tes mains et de ta voix et préférence assumée pour la version des mains, — {prenom}, ton animal attentif à tes narrations doubles 🙌$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai observé comment tu découvres un cadeau inattendu.',$$Joyeux anniversaire. J''ai observé comment tu découvres un cadeau inattendu.
Il y en avait un ce soir. J''ai vu le moment où tu as compris ce que c''était. D''abord l''incompréhension. Puis la reconnaissance. Puis quelque chose de très doux sur ton visage. Ce cheminement en quelques secondes. Joyeux anniversaire, mon humain préféré.
Avec observation du voyage émotionnel d''une surprise réussie et sa beauté brève, — {prenom}, ton animal collectionneur de tes expressions authentiques 🎁$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de rire quand quelqu''un tombe dans un piège verbal.',$$Pour ton anniversaire j''ai observé ta façon de rire quand quelqu''un tombe dans un piège verbal.
Tu ris d''abord. Puis tu aides. C''est l''ordre invariable. Le rire vient naturellement. Puis la générosité suit. Tu ne laisses pas les gens dans l''embarras trop longtemps. Juste assez pour que ce soit drôle. Puis tu tends la main métaphoriquement. Joyeux anniversaire, mon humain préféré.
Avec observation de ton équilibre entre rire et générosité et validation de la séquence, — {prenom}, ton animal expert en timing social 😄$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai regardé par la fenêtre les voitures en bas.',$$Pour ton anniversaire j''ai regardé par la fenêtre les voitures en bas.
Les gens partaient en voiture. La rue normale qui continuait pendant que ta fête se terminait là-haut. Ce contraste entre l''intérieur animé et l''extérieur indifférent. Il dit que ce qui se passe ici est précieux justement parce que le reste du monde n''en sait rien. Joyeux anniversaire, mon humain préféré.
Avec contemplation de la rue nocturne et philosophie de la préciosité de l''intime, — {prenom}, ton animal poète du rebord de fenêtre 🪟$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends pas pourquoi les gens enlèvent leurs chaussures chez certains et pas d''autres.',$$Joyeux anniversaire. Je comprends pas pourquoi les gens enlèvent leurs chaussures chez certains et pas d''autres.
Ce soir personne n''a enlevé ses chaussures. C''est le protocole ici. Cet appartement avec ses chaussures c''est un appartement de vie. De mouvement. De passage joyeux. Joyeux anniversaire, mon humain préféré.
Avec théorie du code des chaussures et classification positive de ton appartement, — {prenom}, ton animal sémiologue des entrées 👟$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon d''allumer la musique sans en faire toute une histoire.',$$Pour ton anniversaire j''ai observé ta façon d''allumer la musique sans en faire toute une histoire.
C''est juste là. La musique. Elle arrive. Personne ne l''a remarqué vraiment. C''est le but. Une présence qui s''installe sans s''imposer. L''art de créer une ambiance sans qu''on la remarque en tant que telle. Joyeux anniversaire, mon humain préféré.
Avec admiration pour ton art de l''ambiance invisible et discrète, — {prenom}, ton animal expert en présences que l''on ressent sans les voir 🎵$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai observé comment tu gères le silence entre deux conversations.',$$Joyeux anniversaire. J''ai observé comment tu gères le silence entre deux conversations.
Tu ne le remplis pas systématiquement. Tu le laisses exister un moment. Tu regardes autour. Tu prends une gorgée. Tu souris sans raison. Ces petits silences dans le bruit. C''est une intelligence sociale que peu ont. Joyeux anniversaire, mon humain préféré, dont les silences sont aussi éloquents que les paroles.
Avec observation de ta gestion des silences et respect pour leur existence consentie, — {prenom}, ton animal appréciant les respirations dans le bruit 🌬️$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé comment tu prépares le café de fin de soirée.',$$Pour ton anniversaire j''ai observé comment tu prépares le café de fin de soirée.
Tu demandes qui en veut. Tu mets la quantité exacte. Tu attends que ça passe. Le café de fin de soirée c''est ta façon de dire encore un moment ensemble avant de se quitter. Joyeux anniversaire, mon humain préféré.
Avec décryptage du café comme signe et de sa préparation soigneuse comme prolongement de l''hospitalité, — {prenom}, ton animal sémiologiste des rituels de fin ☕$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai mémorisé chaque regard échangé entre toi et quelqu''un ce soir.',$$Joyeux anniversaire. J''ai mémorisé chaque regard échangé entre toi et quelqu''un ce soir.
Certains regards disent on se retrouvera plus tard pour parler vraiment. D''autres disent tu vois ce que je vois. D''autres encore disent merci d''être là sans un mot. Ces conversations parallèles que tu avais avec les yeux. Joyeux anniversaire, mon humain préféré.
Avec transcription de tes dialogues oculaires et admiration pour leur densité informationnelle, — {prenom}, ton animal traducteur du regard 👁️$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends pas pourquoi les gens apportent des desserts quand il y a déjà un gâteau.',$$Joyeux anniversaire. Je comprends pas pourquoi les gens apportent des desserts quand il y a déjà un gâteau.
Ce soir il y avait ton gâteau et deux autres choses sucrées. Trois desserts pour huit personnes. Toi tu as tout servi. Tout proposé. Comme si l''abondance de desserts était une bonne nouvelle. Pour toi c''était peut-être le cas. Joyeux anniversaire, mon humain préféré.
Avec analyse de l''économie des desserts festifs et admiration pour ta gestion de l''abondance sucrée, — {prenom}, ton animal observateur de la logistique du sucre 🍮$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de fermer la porte quand le dernier invité est parti.',$$Pour ton anniversaire j''ai observé ta façon de fermer la porte quand le dernier invité est parti.
Lentement. Pas claquée. Fermée avec soin. Comme si tu refermais quelque chose de précieux. Cette porte fermée doucement. Ce geste de fin. C''est un des plus beaux gestes de la soirée. Joyeux anniversaire, mon humain préféré.
Avec observation du geste de fermeture et sa signification de préservation du moment, — {prenom}, ton animal témoin de tes plus beaux gestes de fin 🚪$$,'touching',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. J''ai observé comment tu récupères d''une conversation difficile.',$$Joyeux anniversaire. J''ai observé comment tu récupères d''une conversation difficile.
Il y a eu un moment ce soir. Un sujet qui a failli. Tu l''as senti avant les autres. Tu as dit quelque chose de neutre. Tu as relancé sur autre chose. Si fluide que la plupart n''ont rien remarqué. Joyeux anniversaire, mon humain préféré.
Avec admiration pour ta navigation dans les eaux conversationnelles difficiles, — {prenom}, ton animal expert en déminages sociaux 🎭$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé ta façon de regarder quelqu''un qui ne t''écoute pas vraiment.',$$Pour ton anniversaire j''ai observé ta façon de regarder quelqu''un qui ne t''écoute pas vraiment.
Tu le vois. Ce petit ajustement. Cette façon de continuer à parler mais différemment. Plus court. Pour finir et passer à autre chose. Sans humilier. Sans pointer. Joyeux anniversaire, mon humain préféré.
Avec observation de ta gestion de l''inattention et admiration pour ton élégance du retrait, — {prenom}, ton animal admirateur de ta grâce sociale 💨$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai passé du temps à étudier le tableau dans le couloir.',$$Pour ton anniversaire j''ai passé du temps à étudier le tableau dans le couloir.
Celui que tu ne regardes plus vraiment parce qu''il est là depuis toujours. Ce soir je l''ai regardé longuement. Il y a quelque chose là-dedans que tu aimais assez pour vivre avec chaque jour. Je cherche quoi. Joyeux anniversaire, mon humain préféré.
Avec étude du tableau invisible de ton quotidien et tentative de comprendre ton regard, — {prenom}, ton animal découvreur de ce que tu ne vois plus 🖼️$$,'humorous',true,false,'birthday','chien','from'),

(null,'Joyeux anniversaire. Je comprends pas pourquoi les gens photographient la nourriture avant de manger.',$$Joyeux anniversaire. Je comprends pas pourquoi les gens photographient la nourriture avant de manger.
Ce soir quelqu''un a photographié le gâteau avant de le manger. Puis son assiette. Peut-être c''est une façon de vivre deux fois la même chose. Je comprends un peu mieux maintenant. Joyeux anniversaire, mon humain préféré.
Avec compréhension progressive de la photo avant et réconciliation avec cette pratique, — {prenom}, ton animal dont la compréhension du monde s''affine 📷$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé comment tu ranges les restes dans des boîtes pour les invités.',$$Pour ton anniversaire j''ai observé comment tu ranges les restes dans des boîtes pour les invités.
Chacun repart avec quelque chose. Tu prépares les boîtes à la fin. Tu penses à chacun. Tu sais qui aimait quoi. Ces petits paquets de soirée. Cette façon de prolonger la fête dans leur cuisine le lendemain. Joyeux anniversaire, mon humain préféré.
Avec observation de ta générosité des restes et sa signification de prolongation de la fête, — {prenom}, ton animal admirateur de tes gestes qui durent après toi 📦$$,'humorous',true,false,'birthday','chien','from'),

(null,'Pour ton anniversaire j''ai observé comment tu changes quand tu es dans ton élément.',$$Pour ton anniversaire j''ai observé comment tu changes quand tu es dans ton élément.
Ce soir tu étais dans ton élément. Chez toi. Avec tes gens. Et tu changeais imperceptiblement. Plus grand. Plus fluide. Plus toi. Comme un chien dans son parc préféré. Je sais ce que c''est. Joyeux anniversaire, mon humain préféré.
Avec reconnaissance de notre appartenance commune à cet espace et solidarité de territoire, — {prenom}, ton animal co-habitant de notre élément partagé 🏠$$,'humorous',true,false,'birthday','chien','from')

